#include<bits/stdc++.h>
using namespace std;
int n,m,a[105][105],t[105][105],sum,ans=0x3f3f3f3f;
bool Is_OK(int r,int c){
	if(sum%(r*c)!=0)return 0;
	for(int i=1;i<=n;i++)
		for(int j=1;j<=m;j++)t[i][j]=a[i][j];
	for(int i=1;i<=n;i++)for(int j=1;j<=m;j++)
		if(t[i][j]){
			int num=t[i][j];
			for(int l=i;l<=i+r-1;l++)
				for(int k=j;k<=j+c-1;k++){
					if(l>n||k>m||t[l][k]<num)return 0;
					t[l][k]-=num;
				}
		}
	for(int i=1;i<=n;i++)
		for(int j=1;j<=m;j++)if(t[i][j]!=0)return 0;
	return 1;
}
int main(){
	cin>>m>>n;swap(m,n);
	for(int i=1;i<=n;i++){
		for(int j=1;j<=m;j++){
			cin>>a[i][j];
			sum+=a[i][j];
		}
	}
	for(int r=1;r<=n;r++)
		for(int c=1;c<=m;c++)
			if(Is_OK(r,c))ans=min(ans,sum/(r*c));	
	cout<<ans;
	return 0;
}
